changeSet.sql:
INSERT INTO m_permission (grouping, code, entity_name, action_name, can_maker_checker) SELECT 'SSBENEFICIARYTPT', 'CREATE_SSBENEFICIARYTPT', 'SSBENEFICIARYTPT', 'CREATE', false WHERE NOT EXISTS (SELECT 1 FROM m_permission WHERE code = 'CREATE_SSBENEFICIARYTPT');
INSERT INTO m_permission (grouping, code, entity_name, action_name, can_maker_checker) SELECT 'SSBENEFICIARYTPT', 'UPDATE_SSBENEFICIARYTPT', 'SSBENEFICIARYTPT', 'UPDATE', false WHERE NOT EXISTS (SELECT 1 FROM m_permission WHERE code = 'UPDATE_SSBENEFICIARYTPT');
INSERT INTO m_permission (grouping, code, entity_name, action_name, can_maker_checker) SELECT 'SSBENEFICIARYTPT', 'DELETE_SSBENEFICIARYTPT', 'SSBENEFICIARYTPT', 'DELETE', false WHERE NOT EXISTS (SELECT 1 FROM m_permission WHERE code = 'DELETE_SSBENEFICIARYTPT');
INSERT INTO m_permission (grouping, code, entity_name, action_name, can_maker_checker) SELECT 'SSBENEFICIARYTPT', 'READ_SSBENEFICIARYTPT', 'SSBENEFICIARYTPT', 'READ', false WHERE NOT EXISTS (SELECT 1 FROM m_permission WHERE code = 'READ_SSBENEFICIARYTPT');
INSERT INTO m_role_permission (role_id, permission_id) SELECT r.id, p.id FROM m_role r CROSS JOIN m_permission p WHERE r.name = 'Self Service User' AND p.code IN ('CREATE_SSBENEFICIARYTPT', 'UPDATE_SSBENEFICIARYTPT', 'DELETE_SSBENEFICIARYTPT', 'READ_SSBENEFICIARYTPT') AND NOT EXISTS ( SELECT 1 FROM m_role_permission rp WHERE rp.role_id = r.id AND rp.permission_id = p.id );
